  OR {  
    AND {  
      (`BE is a less-than expression (LTExpr)`),  
      EXISTS (`expression L`, `expression R`) {  
        AND {  
          (`L is the left operand of BE`),  
          (`R is the right operand of BE`),  
          OR {  
            (`L is an array length field read (ArrayLengthRead) and R is an integer or long literal with value 0`),  
            (`L is a string length method call (StringLengthRead) and R is an integer or long literal with value 0`),  
            (`L is a collection size method call (CollectionSizeCall) and R is an integer or long literal with value 0`),  
            (`L is a map size method call (MapSizeCall) and R is an integer or long literal with value 0`)  
          }  
        }  
      }  
    },  
    AND {  
      (`BE is a greater-than expression (GTExpr)`),  
      EXISTS (`expression L`, `expression R`) {  
        AND {  
          (`L is the left operand of BE`),  
          (`R is the right operand of BE`),  
          OR {  
            (`L is an integer or long literal with value 0 and R is an array length field read (ArrayLengthRead)`),  
            (`L is an integer or long literal with value 0 and R is a string length method call (StringLengthRead)`),  
            (`L is an integer or long literal with value 0 and R is a collection size method call (CollectionSizeCall)`),  
            (`L is an integer or long literal with value 0 and R is a map size method call (MapSizeCall)`)  
          }  
        }  
      }  
    },  
    AND {  
      (`BE is a greater-than-or-equal expression (GEExpr)`),  
      EXISTS (`expression L`, `expression R`) {  
        AND {  
          (`L is the left operand of BE`),  
          (`R is the right operand of BE`),  
          OR {  
            (`L is an array length field read (ArrayLengthRead) and R is an integer or long literal with value 0`),  
            (`L is a string length method call (StringLengthRead) and R is an integer or long literal with value 0`),  
            (`L is a collection size method call (CollectionSizeCall) and R is an integer or long literal with value 0`),  
            (`L is a map size method call (MapSizeCall) and R is an integer or long literal with value 0`)  
          }  
        }  
      }  
    },  
    AND {  
      (`BE is a less-than-or-equal expression (LEExpr)`),  
      EXISTS (`expression L`, `expression R`) {  
        AND {  
          (`L is the left operand of BE`),  
          (`R is the right operand of BE`),  
          OR {  
            (`L is an integer or long literal with value 0 and R is an array length field read (ArrayLengthRead)`),  
            (`L is an integer or long literal with value 0 and R is a string length method call (StringLengthRead)`),  
